def process_sentence(sentence):
    # Ignore anything after '|' character
    if '|' in sentence:
        sentence = sentence.split('|')[0]

    # Split the sentence into words
    words = sentence.split()
    name = words[0]  # First word is the name
    N = int(words[2])  # N is the third word (number of items)
    M = int(words[5])  # M is the sixth word (number of items)

    if 'has' in words and 'buys' in words:
        # Pattern 1
        return N + M
    elif 'had' in words and 'gave' in words:
        # Pattern 2
        if M <= N:
            return N - M
        else:
            return 'INVALID'
    elif 'has' in words and 'gives' in words:
        # Pattern 3
        if M <= N:
            return N - M
        else:
            return 'INVALID'
    else:
        return 'INVALID'

